import uuid
import boto3
from botocore.config import Config as BotoConfig
from config import AWS_REGION, S3_BUCKET


class S3Service:
    ALLOWED_TYPES = {'image/jpeg', 'image/png', 'image/webp', 'video/mp4', 'application/pdf'}

    def __init__(self):
        self.client = boto3.client(
            's3',
            region_name=AWS_REGION,
            config=BotoConfig(signature_version='s3v4')
        )
        self.bucket = S3_BUCKET

    def generate_upload_url(self, filename: str, content_type: str, expires: int = 900) -> dict:
        if content_type not in self.ALLOWED_TYPES:
            raise ValueError(f'Content type {content_type} not allowed')
        ext = filename.rsplit('.', 1)[-1] if '.' in filename else 'bin'
        key = f'uploads/{uuid.uuid4().hex}.{ext}'
        url = self.client.generate_presigned_url(
            'put_object',
            Params={'Bucket': self.bucket, 'Key': key, 'ContentType': content_type},
            ExpiresIn=expires
        )
        return {'upload_url': url, 'key': key}

@api_bp.route('/api/upload-url', methods=['POST'])
def get_upload_url():
    from services.s3_service import S3Service
    data = request.get_json()
    filename = data.get('filename')
    content_type = data.get('content_type')
    if not filename or not content_type:
        return jsonify({'error': 'filename and content_type required'}), 400
    try:
        s3 = S3Service()
        result = s3.generate_upload_url(filename, content_type)
        return jsonify(result)
    except ValueError as e:
        return jsonify({'error': str(e)}), 400
